import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';
import { parseGgProgram } from '@a0n/aeon-logic';
import type { GgProgram } from '@a0n/aeon-logic';
import { runGGTestFile } from '../gg-test-runner';

